206	        const long long MAX_XJ_INITIAL_HIGH_BOUND = BASE_WEIGHT * (1LL * N_items_global / std::max(1, D_groups_global) + 10);
207	
208	        for (int j = 2; j < k_pivots_chosen; ++j) {
209	            int current_pivot_idx = sorted_pivot_item_indices[j];
