216	                estimated_weights[current_pivot_idx] = std::max(1LL, estimated_weights[prev_pivot_idx] * FACTOR_LT_NUM / 100);
217	            } else {
218	                long long X_low_bound_val = 1;
219	                long long X_high_bound_val = MAX_XJ_INITIAL_HIGH_BOUND;
